BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?view ?type ?name WHERE {
  {
    ?apsBS v:NamedElement_name ?dummy .
  }
  BIND(<http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Project%2520Systems%2520Engineering::01%2520Components::Operational::TMT%2520Observatory%2520System::Black%2520Box%2520Specifications%2520for%2520Suppliers::APS%2520Black%2520Box%2520Specification%2520TMT> AS ?apsBS)

  ?apsBS (vocab:Element_ownedElement+|vocab:Package_packagedElement+|^vocab:Element_owner+)? ?view .
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?view ?type ?name WHERE {
  ?view rdf:type ?type ;
        vocab:NamedElement_name ?name .

  FILTER(
    CONTAINS(LCASE(STR(?name)), LCASE("Requirements%20Flow-down%20Views")) &&
    CONTAINS(LCASE(STR(?name)), LCASE("APS"))
  )
}
ORDER BY ?name
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?pkg ?pkgName ?view ?viewName WHERE {
  ?pkg rdf:type ?pkgType ;
       vocab:NamedElement_name ?pkgName .
  FILTER(CONTAINS(LCASE(STR(?pkgName)), LCASE("Requirements%20Flow-down%20Views::APS%20Performance%20Requirements")))

  OPTIONAL {
    ?pkg vocab:Element_ownedElement+ ?view .
    ?view vocab:NamedElement_name ?viewName .
  }
  OPTIONAL {
    ?pkg vocab:Package_packagedElement+ ?view .
    ?view vocab:NamedElement_name ?viewName .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?view ?type ?name WHERE {
  ?view rdf:type ?type ;
        vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("APS%20Performance%20Requirements")))
}
LIMIT 25
